import java.util.HashMap;
import java.util.Map;
import java.util.logging.Level;
import java.util.logging.Logger;

/**
 * Template service class for handling user profile page template rendering
 * 
 * <p>This service uses Freemarker template engine to render user profile pages
 * with security restrictions to prevent template injection attacks.</p>
 */
public class TemplateService {

    private static final Logger LOGGER = Logger.getLogger(TemplateService.class.getName());

    private static final int MAX_TEMPLATE_LENGTH = 100000; // 100KB limit
    private static final int MAX_USERNAME_LENGTH = 255;

    private final Configuration freemarkerConfig;

    /**
     * Constructs a new TemplateService with secure Freemarker configuration
     */
    public TemplateService() {
        this.freemarkerConfig = new Configuration(Configuration.VERSION_2_3_31);
        configureFreemarker();
    }

    /**
     * Configures Freemarker with security-focused settings
     */
    private void configureFreemarker() {
        // Set default encoding for international character support
        freemarkerConfig.setDefaultEncoding("UTF-8");

        // Set template exception handler for better error reporting
        freemarkerConfig.setTemplateExceptionHandler(TemplateExceptionHandler.RETHROW_HANDLER);

        // Disable localized lookup to prevent file system access
        freemarkerConfig.setLocalizedLookup(false);

        // Set API builtin to prevent access to dangerous methods
        freemarkerConfig.setAPIBuiltinEnabled(false);

        // Disable new builtin to prevent object instantiation
        freemarkerConfig.setNewBuiltinClassResolver(
            freemarker.core.TemplateClassResolver.SAFER_RESOLVER
        );

        // Set log template exceptions to false for production
        freemarkerConfig.setLogTemplateExceptions(false);

        // Wrap unchecked exceptions
        freemarkerConfig.setWrapUncheckedExceptions(true);

        // Set fallback on null for safer template processing
        freemarkerConfig.setFallbackOnNullLoopVariable(false);

        LOGGER.info("Freemarker configuration initialized with security settings");
    }

    /**
     * Renders the user profile page based on username and template content
     * 
     * <p>This method processes user-provided template content using Freemarker
     * template engine with security restrictions enabled.</p>
     * 
     * @param username the username to display in the profile
     * @param templateContent the user-provided template content (supports Freemarker syntax)
     * @return the rendered HTML string
     * @throws IllegalArgumentException if username or template content is blank or exceeds limits
     * @throws RuntimeException if template processing fails
     */
    public String renderUserProfile(String username, String templateContent) {
        // Validate inputs
        validateInputs(username, templateContent);

        LOGGER.log(Level.FINE, "Rendering profile for user: {0}", username);

        try {
            // Create template from string content
            Template template = createTemplate(templateContent);

            // Prepare data model with user information
            Map<String, Object> dataModel = createDataModel(username);

            // Render template to string
            return processTemplate(template, dataModel);

        } catch (ParseException e) {
            String errorMsg = String.format(
                "Template syntax error at line %d, column %d: %s",
                e.getLineNumber(),
                e.getColumnNumber(),
                e.getMessage()
            );
            LOGGER.log(Level.WARNING, errorMsg, e);
            throw new RuntimeException(errorMsg, e);

        } catch (IOException e) {
            String errorMsg = "IO exception occurred during template processing: " + e.getMessage();
            LOGGER.log(Level.SEVERE, errorMsg, e);
            throw new RuntimeException(errorMsg, e);

        } catch (TemplateException e) {
            String errorMsg = String.format(
                "Template rendering exception: %s",
                e.getMessage()
            );
            LOGGER.log(Level.WARNING, errorMsg, e);
            throw new RuntimeException(errorMsg, e);

        } catch (Exception e) {
            String errorMsg = "Unexpected error during template rendering: " + e.getMessage();
            LOGGER.log(Level.SEVERE, errorMsg, e);
            throw new RuntimeException(errorMsg, e);
        }
    }

    /**
     * Validates input parameters
     * 
     * @param username the username to validate
     * @param templateContent the template content to validate
     * @throws IllegalArgumentException if validation fails
     */
    private void validateInputs(String username, String templateContent) {
        if (StringUtils.isBlank(username)) {
            throw new IllegalArgumentException("Username cannot be empty or blank");
        }

        if (StringUtils.isBlank(templateContent)) {
            throw new IllegalArgumentException("Template content cannot be empty or blank");
        }

        if (username.length() > MAX_USERNAME_LENGTH) {
            throw new IllegalArgumentException(
                String.format("Username exceeds maximum length of %d characters", MAX_USERNAME_LENGTH)
            );
        }

        if (templateContent.length() > MAX_TEMPLATE_LENGTH) {
            throw new IllegalArgumentException(
                String.format("Template content exceeds maximum length of %d characters", MAX_TEMPLATE_LENGTH)
            );
        }
    }

    /**
     * Creates a Freemarker template from string content
     * 
     * @param templateContent the template content
     * @return the compiled template
     * @throws IOException if template creation fails
     */
    private Template createTemplate(String templateContent) throws IOException {
        // Use a unique name for each template to avoid caching issues
        String templateName = "userProfile_" + System.currentTimeMillis();
        return new Template(templateName, templateContent, freemarkerConfig);
    }

    /**
     * Creates the data model for template processing
     * 
     * @param username the username to include in the model
     * @return the data model map
     */
    private Map<String, Object> createDataModel(String username) {
        Map<String, Object> dataModel = new HashMap<>();

        // Add username to the model
        dataModel.put("username", escapeHtml(username));

        // Add additional safe metadata if needed
        dataModel.put("timestamp", System.currentTimeMillis());

        return dataModel;
    }

    /**
     * Processes the template with the given data model
     * 
     * @param template the template to process
     * @param dataModel the data model
     * @return the rendered string
     * @throws TemplateException if template processing fails
     * @throws IOException if IO error occurs
     */
    private String processTemplate(Template template, Map<String, Object> dataModel) 
            throws TemplateException, IOException {

        try (StringWriter writer = new StringWriter()) {
            template.process(dataModel, writer);
            writer.flush();
            return writer.toString();
        }
    }

    /**
     * Escapes HTML special characters to prevent XSS attacks
     * 
     * @param input the input string
     * @return the escaped string
     */
    private String escapeHtml(String input) {
        if (input == null) {
            return "";
        }

        return input.replace("&", "&amp;")
                   .replace("<", "&lt;")
                   .replace(">", "&gt;")
                   .replace("\"", "&quot;")
                   .replace("'", "&#x27;")
                   .replace("/", "&#x2F;");
    }

    /**
     * Gets the Freemarker configuration (for testing purposes)
     * 
     * @return the configuration object
     */
    Configuration getFreemarkerConfig() {
        return freemarkerConfig;
    }
}

